// // This module compares two 4-bit numbers and sets 'larger' to HIGH if A is greater than or equal to B
module top_module(input [3:0] A, input [3:0] B, output reg smaller);always @ (A,B)
begin 
    if (A[3:0] < B[3:0])
        smaller = 1'b1;
    else
        smaller = 1'b0;
end 
endmodule
